import React, {type ReactNode} from "react";
import type {ICircularProgressProps} from "@lmb-it/kitsconcerto-types";
import { useKitsTheme } from "../../contexts/Theme";

const CircularProgress: React.FC<ICircularProgressProps> = ({
                                                               size = 100,
                                                               strokeWidth = 8,
                                                               value,
                                                               color,
                                                               trackColor,
                                                               loading = false,
                                                               children,
                                                           }) => {
    const { resolveToken } = useKitsTheme();
    const resolvedColor = color ?? resolveToken('primary');
    const resolvedTrackColor = trackColor ?? resolveToken('gray.200');

    const radius = (size - strokeWidth) / 2; // Calculate the radius
    const circumference = 2 * Math.PI * radius; // Calculate the circumference
    const offset = circumference - (value / 100) * circumference; // Calculate the stroke offset for progress

    return (
        <div
            style={{
                position: "relative",
                width: size,
                height: size,
                display: "inline-flex",
                justifyContent: "center",
                alignItems: "center",
            }}
        >
            <svg
                width={size}
                height={size}
                style={{
                    animation: loading ? "spin 1s linear infinite" : "none", // Spinner animation
                }}
            >
                {/* Background track */}
                <circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    fill="none"
                    stroke={resolvedTrackColor}
                    strokeWidth={strokeWidth}
                />
                {/* Progress circle */}
                <circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    fill="none"
                    stroke={resolvedColor}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    style={{
                        transition: loading ? "none" : "stroke-dashoffset 0.3s ease",
                    }}
                />
            </svg>
            {/* Center Content */}
            <div
                style={{
                    position: "absolute",
                    top: "50%",
                    left: "50%",
                    transform: "translate(-50%, -50%)",
                    display: "flex",
                    justifyContent: "center",
                    alignItems: "center",
                }}
            >
                {children}
            </div>
            {/* Spinner Animation */}
            <style>
                {`
          @keyframes spin {
            0% {
              transform: rotate(0deg);
            }
            100% {
              transform: rotate(360deg);
            }
          }
        `}
            </style>
        </div>
    );
};

export default CircularProgress;
